n pairs({CFrame.new(k,0.5,-3.5),CFrame.new(k,0.5,3.5),CFrame.new(-3.5,0.5,k),CFrame.new(3.5,0.5,k)}) do local b=Instance.new("Part",m) b.Size=Vector3.new(0.2,8,0.2) b.CFrame=h.CFrame*o b.Anchored=true end end end end}) T3:CreateToggle({Name="Loop Fling",Callback=function(v) LF=v while LF do task.wait(0.01) pcall(function() local p=gT() local m=LP.Character.HumanoidRootPart m.CFrame=p.Character.HumanoidRootPart.CFrame m.Velocity=Vector3.new(9e9,9e9,9e9) end) end end}) T4:CreateToggle({Name="Kill Aura",Callback=function(v) KA=v while KA do task.wait(0.1) for _,p in pairs(P:GetPlayers()) do if p~=LP and p.Character and (LP.Character.HumanoidRootPart.Position-p.Character.HumanoidRootPart.Position).Magnitude<15 then pcall(function() LP.Character:FindFirstChildOfClass("Tool"):Activate() end) end end end end}) T5:CreateButton({Name="Mage Anim",Callback=function() sA("707827244") end}) T5:CreateButton({Name="Ninja Anim",Callback=function() sA("616111377") end}) T6:CreateInput({Name="Music ID",Callback=function(t) _G.MID=t end}) T6:CreateButton({Name="Play Sound 🔊",Callback=function() local s=workspace:FindFirstChild("N0XY_Radio") or Instance.new("Sound",workspace) s.Name="N0XY_Radio" s.SoundId="rbxassetid://".._G.MID s:Play() end}) RS.Stepped:Connect(function() if NC and LP.Character then for _,p in pairs(LP.Character:GetDescendants()) do if p:IsA("BasePart") then p.CanCollide=false end end end if F and LP.Character then LP.Character.HumanoidRootPart.Velocity=Vector3.new(0,0,0) end end) task.spawn(function() while task.wait(0.1) do pcall(function() LP.Character.Humanoid.WalkSpeed=WS LP.Character.Humanoid.JumpPower=JP end) end end)
